def gen(rng, size):
    n = min(1000, max(1, size))
    seen = set()
    stones = []
    while len(stones) < n:
        r, c = rng.randint(0, 9999), rng.randint(0, 9999)
        if (r, c) not in seen:
            seen.add((r, c))
            stones.append([r, c])
    return [stones]

