class Solution:
    def removeStones(self, stones):
        parent = {}
        def find(x):
            if x not in parent:
                parent[x] = x
            while parent[x] != x:
                parent[x] = parent.setdefault(parent[x], parent[x])
                x = parent[x]
            return x
        def union(a, b):
            a, b = find(a), find(b)
            if a != b:
                parent[a] = b
        for r, c in stones:
            union(r, ~c)
        return len(stones) - len({find(r) for r, c in stones})

